from __future__ import annotations

from dataclasses import dataclass
from typing import Optional

from workers_control.core.interactors.request_coordination_transfer import (
    RequestCoordinationTransferInteractor as Interactor,
)
from workers_control.web.forms import RequestCoordinationTransferForm
from workers_control.web.forms.fields import parse_formfield
from workers_control.web.forms.formfield_parsers import UuidParser
from workers_control.web.session import Session


@dataclass
class RequestCoordinationTransferController:
    session: Session
    uuid_parser: UuidParser

    def import_form(self, form_data: dict) -> Optional[RequestCoordinationTransferForm]:
        form = RequestCoordinationTransferForm(form_data)
        if form.is_valid() and form.cleaned_data.get("uuid") is not None:
            uuid = parse_formfield(form.cleaned_data["uuid"], self.uuid_parser)
            if uuid is not None and uuid > 0:
                return form
        return None

    def handle(self, form_data: dict) -> Optional[str]:
        form = self.import_form(form_data)
        if form is None:
            return None
        interactor = Interactor(session=self.session)
        result = interactor.transfer(form.cleaned_data)
        return result
